parameters.jsCode:
const cfg = $('Normalize Resume Text From PDF').first().json;

const terms = String(cfg.search_terms || '')
  .split(',')
  .map(t => t.trim())
  .filter(Boolean)
  .slice(0, 5);

if (!terms.length) {
  throw new Error("No search terms found.");
}

return terms.map(search_term => ({
  json: {
    search_term,
    city: cfg.city || "",
    job_type: cfg.job_type || "Any",
    digest_email: cfg.digest_email,
    max_jobs_to_rerank: Number(cfg.max_jobs_to_rerank || 50),

    name: cfg.name,
    skills: cfg.skills,
    projects: cfg.projects,
    education: cfg.education,
    certifications: cfg.certifications,
    internships: cfg.internships
  }
}));

function sqlString(v) {
  if (v === null || v === undefined || v === '') return 'NULL';
  return `'${String(v).replace(/'/g, "''")}'`;
}

function sqlNumber(v) {
  return v === null || v === undefined || v === '' || Number.isNaN(Number(v))
    ? 'NULL'
    : String(Number(v));
}

function sqlDate(v) {
  return v ? `${sqlString(v)}::timestamptz` : 'NULL';
}

return items
  .filter(item => item.json && item.json.url && item.json.job_id)
  .map(item => {
    const j = item.json;

    const sql = `INSERT INTO jobs (
  job_id,
  source,
  title,
  company,
  location,
  work_type,
  experience_required,
  salary_min,
  salary_max,
  salary_raw,
  salary_confidence,
  description,
  url,
  date_posted
) VALUES (
  ${sqlString(j.job_id)},
  ${sqlString(j.source)},
  ${sqlString(j.title)},
  ${sqlString(j.company)},
  ${sqlString(j.location)},
  ${sqlString(j.work_type)},
  ${sqlString(j.experience_required)},
  ${sqlNumber(j.salary_min)},
  ${sqlNumber(j.salary_max)},
  ${sqlString(j.salary_raw)},
  ${sqlString(j.salary_confidence)},
  ${sqlString(j.description)},
  ${sqlString(j.url)},
  ${sqlDate(j.date_posted)}
)
ON CONFLICT (job_id) DO UPDATE SET
  source = EXCLUDED.source,
  title = EXCLUDED.title,
  company = EXCLUDED.company,
  location = EXCLUDED.location,
  work_type = EXCLUDED.work_type,
  experience_required = EXCLUDED.experience_required,
  salary_min = COALESCE(jobs.salary_min, EXCLUDED.salary_min),
  salary_max = COALESCE(jobs.salary_max, EXCLUDED.salary_max),
  salary_raw = COALESCE(NULLIF(jobs.salary_raw, ''), EXCLUDED.salary_raw),
  salary_confidence = CASE
    WHEN jobs.salary_confidence = 'explicit'
    THEN jobs.salary_confidence
    ELSE EXCLUDED.salary_confidence
  END,
  description = EXCLUDED.description,
  date_posted = COALESCE(jobs.date_posted, EXCLUDED.date_posted)
RETURNING *;`;

    return {
      json: {
        ...j,
        sql
      }
    };
  });

const cfg = $('Normalize Resume Text From PDF').first().json;

// ---------- Resume Skills ----------
const skills = Object.values(cfg.skills || {})
  .flat()
  .filter(Boolean)
  .map(s => String(s).trim());

const resumeSkills = [...new Set(skills)];

// ---------- Job ----------
const job = {
  job_id: $json.id,
  title: $json.title || "",
  company: $json.company || "",
  location: $json.location || "",
  work_type: $json.work_type || "",
  experience_required: $json.experience_required || "",
  description: String($json.description || "")
    .replace(/\s+/g, " ")
    .trim()
    .slice(0, 250)
};

// ---------- Prompt ----------
const prompt = `
You are an ATS recruiter.

Evaluate how well the candidate matches this job.

Rules:
- Use ONLY the information provided.
- Do NOT invent skills, technologies, experience, or requirements.
- Identify technologies, programming languages, frameworks, databases, cloud platforms, tools, and software explicitly mentioned or clearly implied in the job description.
- matching_skills: Include only skills present in BOTH the candidate's skills and the job requirements.
- missing_skills: Include only skills required by the job but NOT present in the candidate's skills.
- Do not include duplicate skills.
- Prefer specific technologies (e.g., Python, Docker, AWS, TensorFlow) over generic terms (e.g., Programming, Development).
- Keep the reasoning concise (maximum 2 sentences).
- Return ONLY valid JSON matching the output schema.

Candidate Skills:
${resumeSkills.join(", ")}

Job Title:
${job.title}

Company:
${job.company}

Location:
${job.location}

Experience:
${job.experience_required}

Job Description:
${job.description}
`;

return {
  job_id: job.job_id,
  prompt
};

function asObject(value) {
  if (!value) return {};

  if (typeof value === "object") return value;

  const cleaned = String(value)
    .replace(/^```(?:json)?\s*/i, "")
    .replace(/\s*```$/i, "")
    .trim();

  return JSON.parse(cleaned);
}

function arr(v) {
  return Array.isArray(v)
    ? v.filter(Boolean).map(String)
    : [];
}

const ai = asObject(
  $json.output ??
  $json.text ??
  $json
);

const prep = $('Prepare Rerank Prompt').item.json;

return {
  job_id: prep.job_id,

  compatibility_score: Number(ai.compatibility_score ?? 0),

  reasoning: String(ai.reasoning || "").trim(),

  matching_skills: arr(ai.matching_skills),

  missing_skills: arr(ai.missing_skills)
};

const TOP_K = 5;

// ---------- Helpers ----------

function arr(v) {
  if (Array.isArray(v)) return v;
  if (!v) return [];
  try {
    const parsed = typeof v === "string" ? JSON.parse(v) : v;
    return Array.isArray(parsed) ? parsed : [];
  } catch {
    return [];
  }
}

function esc(v) {
  return String(v ?? "").replace(/[&<>"']/g, c => ({
    "&": "&amp;",
    "<": "&lt;",
    ">": "&gt;",
    '"': "&quot;",
    "'": "&#39;"
  }[c]));
}

function list(items) {
  const values = arr(items).filter(Boolean);

  if (values.length === 0) {
    return "<li>None identified</li>";
  }

  return values
    .map(v => `<li>${esc(v)}</li>`)
    .join("");
}

function salary(j) {

  if (j.salary_min == null && j.salary_max == null) {
    return "Not listed";
  }

  const min = j.salary_min != null
    ? Number(j.salary_min).toLocaleString("en-IN")
    : "";

  const max = j.salary_max != null
    ? Number(j.salary_max).toLocaleString("en-IN")
    : "";

  const range =
    min && max && min !== max
      ? `${min} - ${max}`
      : (min || max);

  const confidence =
    j.salary_confidence === "explicit"
      ? "confirmed"
      : j.salary_confidence === "inferred"
      ? "estimated"
      : "unknown";

  return `${range} (${confidence})`;
}

// ---------- Jobs ----------

const jobs = items
  .map(i => i.json)
  .filter(j => j && j.id && j.url && !j.emailed)
  .sort((a, b) => Number(b.compatibility_score || 0) - Number(a.compatibility_score || 0))
  .slice(0, TOP_K);

const cfg = $("Workflow Config").first().json;

const to = cfg.digest_email;

const resumeHash = jobs.length
  ? jobs[0].resume_hash
  : "";

const date = new Date().toLocaleDateString("en-IN", {
  weekday: "long",
  year: "numeric",
  month: "short",
  day: "numeric"
});

let html;

// ---------- Empty Digest ----------

if (jobs.length === 0) {

  html = `
<div style="font-family:Arial,sans-serif;line-height:1.6;color:#111;">
  <h2>Weekly Job Digest</h2>

  <p>
    The automation ran on <strong>${esc(date)}</strong>.
  </p>

  <p>
    No new jobs were found that matched this resume.
  </p>
</div>
`;

} else {

  const cards = jobs.map(j => `

<div style="border:1px solid #ddd;border-radius:8px;padding:18px;margin-bottom:18px;background:#fff;">

  <h3 style="margin:0 0 8px 0;">
    ${esc(j.title)}
  </h3>

  <p style="margin:0 0 8px;color:#444;">
    ${esc(j.company || "Unknown Company")}<br>
    ${esc(j.location || "Unknown Location")}
  </p>

  <p>
    <strong>Compatibility Score:</strong>
    ${esc(j.compatibility_score)}%
  </p>

  <p>
    <strong>Salary:</strong>
    ${esc(salary(j))}
  </p>

  <p>
    <strong>Reasoning:</strong><br>
    ${esc(j.rerank_reasoning || "No reasoning available")}
  </p>

  <p><strong>Matching Skills</strong></p>

  <ul>
    ${list(j.matching_skills)}
  </ul>

  <p><strong>Missing Skills</strong></p>

  <ul>
    ${list(j.missing_skills)}
  </ul>

  <p style="margin-top:18px;">
    <a href="${esc(j.url)}"
       style="background:#0b57d0;color:white;padding:10px 18px;border-radius:5px;text-decoration:none;">
      Apply Now
    </a>
  </p>

</div>

`).join("");

  html = `
<div style="font-family:Arial,sans-serif;line-height:1.6;color:#111;">

  <h2>Weekly Job Digest</h2>

  <p>
    Generated on <strong>${esc(date)}</strong>
  </p>

  ${cards}

</div>
`;

}

// ---------- SQL to mark emailed ----------

let mark_emailed_sql = "SELECT 1;";

if (jobs.length > 0) {

  const ids = jobs
    .map(j => `'${String(j.id).replace(/'/g, "''")}'::uuid`)
    .join(", ");

  mark_emailed_sql = `
UPDATE jobs
SET emailed = true
WHERE id IN (${ids});
`;

}

// ---------- Output ----------

return [{
  json: {
    to,

    subject: jobs.length
      ? `Weekly Job Digest - Top ${jobs.length} Job Matches`
      : "Weekly Job Digest - No New Matches",

    html,

    job_ids: jobs.map(j => j.id),

    mark_emailed_sql
  }
}];

const cfg = $('Workflow Config').first().json;

// Ensure the LLM returned a parsed resume
if (!$json.name && !$json.skills && !$json.projects) {
  throw new Error("Resume parsing failed. No structured resume data was found.");
}

return [{
  json: {
    // Workflow config
    ...cfg,

    // Parsed resume
    name: $json.name || "",

    skills: $json.skills || {
      programming_languages: [],
      frameworks_libraries: [],
      databases: [],
      cloud_platforms: [],
      tools: [],
      technologies: [],
      other: []
    },

    projects: $json.projects || [],
    internships: $json.internships || [],
    certifications: $json.certifications || [],
    education: $json.education || [],

    // Metadata
    resume_source: "pdf",
    parsed_at: new Date().toISOString()
  }
}];

parameters.text:
=You are an expert ATS resume parser.

Extract structured information from the resume accurately.

Rules:
- Return only information explicitly present in the resume.
- Never infer, guess, or hallucinate information.
- If a field is missing, return an empty array.
- Preserve the original wording where appropriate.
- For projects, extract the project title and the technologies, programming languages, frameworks, tools, databases, or cloud services mentioned.
- Ignore contact details except the candidate's name.
- Group skills into the most appropriate categories.

Always return output in this exact structure:

{
  "output": {
    "name": "John Doe",
    "skills": {
      "programming_languages": [],
      "frameworks_libraries": [],
      "databases": [],
      "cloud_platforms": [],
      "tools": [],
      "technologies": [],
      "other": []
    },
    "projects": [
      {
        "title": "Project Name",
        "technologies": []
      }
    ],
    "internships": [
      {
        "company": "Company Name",
        "role": "Intern Role"
      }
    ],
    "certifications": [],
    "education": [
      {
        "degree": "",
        "institution": "",
        "cgpa": ""
      }
    ]
  }
}

Return ONLY the JSON object.
Do not include markdown, explanations, or code fences.

Resume:

{{$json.text}}

parameters.jsCode:
const raw = $json.text ?? $json.output ?? '';

const cleaned = String(raw)
  .replace(/^```(?:json)?\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

const parsed = JSON.parse(cleaned);

// Normalize: ensure all expected fields exist
const output = parsed.output ?? parsed;

return [{
  json: {
    name: output.name ?? '',

    skills: {
      programming_languages: output.skills?.programming_languages ?? [],
      frameworks_libraries: output.skills?.frameworks_libraries ?? [],
      databases: output.skills?.databases ?? [],
      cloud_platforms: output.skills?.cloud_platforms ?? [],
      tools: output.skills?.tools ?? [],
      technologies: output.skills?.technologies ?? [],
      other: output.skills?.other ?? []
    },

    projects: (output.projects ?? []).map(p => ({
      title: p.title ?? '',
      technologies: p.technologies ?? []
    })),

    internships: (output.internships ?? []).map(i => ({
      company: i.company ?? '',
      role: i.role ?? ''
    })),

    certifications: output.certifications ?? [],

    education: (output.education ?? []).map(e => ({
      degree: e.degree ?? '',
      institution: e.institution ?? '',
      cgpa: e.cgpa ?? ''
    })),

    resume_text: $('HTTP Request1').first().json.text ?? ''
  }
}];

return {
  json: {
    source: "adzuna",
    job_id: $json.id,

    title: $json.title || "",

    company: $json.company?.display_name || "",

    location: $json.location?.display_name || "",

    description: $json.description || "",

    url: $json.redirect_url || "",

    salary_min: $json.salary_min ?? null,

    salary_max: $json.salary_max ?? null,

    salary_raw: $json.salary_is_predicted ?? "",

    date_posted: $json.created ?? null
  }
};
